/* techniques q16 (54 mục) — engine-API đợt 1663-1692 Ch.1692 */
window.__LIBQ=window.__LIBQ||{};window.__LIBQ["tien-nghich"]=window.__LIBQ["tien-nghich"]||{};window.__LIBQ["tien-nghich"]["q16"]=window.__LIBQ["tien-nghich"]["q16"]||{};window.__LIBQ["tien-nghich"]["q16"]["techniques"]={"updatedAt":"2026-07-15","count":54,"techniques":[{"id":"ngu-hanh-quy-nhat-tran","name":"Ngũ Hành Quy Nhất trận","cn":"","aliases":["Ngũ hành đại trận","Ngũ Hành đại trận"],"loai":"bi-thuat","loaiLabel":"Trận pháp","phamCap":"Không rõ (cấp tinh cầu)","hePhai":"Quy Nhất Tông","soHuu":["Quy Nhất Tông"],"blurb":"Đại trận hộ tinh của Ngũ Hành tinh, tạo bởi năm quầng sáng ngũ sắc bao quanh tinh cầu. Chứa lực lượng Ngũ Hành liên tục công kích kẻ xâm nhập, có năm quan và cửu chuyển.","detail":"Trận pháp hộ tinh cấp tinh cầu của Quy Nhất Tông trên Ngũ Hành tinh. Năm quầng sáng ngũ sắc xoay tròn bao quanh tinh cầu, chứa lực lượng hỏa diễm, hàn thủy, kim lực, thổ và mộc khí liên tục công kích kẻ xâm nhập. Có năm quan (ngũ quan); nếu qua hết ngũ quan thì trận pháp diễn biến thành Ngũ Hành quy nhất với cửu chuyển. Cường giả tầng cao Quy Nhất Tông tự nhận lọt vào cũng chỉ chống đỡ được nửa nén nhang, dừng ở hỏa hoành quang.","congNang":["Trận pháp hộ tinh cấp tinh cầu, ngăn xâm nhập bằng công kích Ngũ Hành liên tục","Năm quan thử thách, qua hết thì diễn biến thành Ngũ Hành quy nhất cửu chuyển"],"dacDiem":"Ngũ sắc xoay tròn quanh tinh cầu, lực lượng Ngũ Hành gồm hỏa diễm, hàn thủy, kim lực, thổ, mộc khí","uyLuc":"Cường giả Quy Nhất Tông tự nhận lọt vào chỉ chống đỡ nửa nén nhang","tabs":{"tienTrinh":[{"chuong":"@c1634","loai":"xuất hiện","importance":"major","giaiDoan":"Vương Lâm bước vào trận","text":"Vương Lâm bước vào quầng sáng ngũ sắc của Ngũ Hành đại trận, chịu công kích liên tiếp từ lực lượng Ngũ Hành. Lão già hắc bào tầng cao tháp tuyên bố trận pháp cực lợi hại, bản thân lọt vào cũng chỉ chống đỡ nửa nén nhang.","anchor":"Ngũ Hành đại trận này dù là lão phu lọt vào cũng chỉ có thể chống đỡ trong thời gian nửa nén nhang mà thôi"}]},"nguon":["@c1634"]},{"id":"dai-dia-tho-tran","name":"Đại địa thổ trận","cn":"","loai":"bi-thuat","loaiLabel":"Trận pháp","phamCap":"Không rõ","hePhai":"Quy Nhất tông","soHuu":["Quy Nhất tông"],"blurb":"Trận thứ nhất của Ngũ hành đại trận, thế giới chỉ có đại địa trên dưới không có bầu trời, gồm chín biến mỗi biến mạnh hơn.","detail":"Trận đầu tiên trong năm quan của Ngũ hành đại trận bảo vệ Ngũ Hành tinh. Bên trong trận chỉ có đại địa phía trên và dưới, không bầu trời. Sơ biến: chín cơn lốc hóa thành chín mặt người bùn đất tấn công. Đệ nhị biến: hai mặt đất ép chặt mục tiêu không còn khe hở. Tổng cộng chín biến. Bị Vương Lâm dùng thân thể Đạo cổ phá toàn bộ sơ biến và đệ nhị biến, đồng thời thu luôn trận linh — dúm bùn đất tỏa linh khí dày đặc.","congNang":["Tạo không gian trận chỉ có đại địa, triệu hồi chín mặt người bùn đất tấn công, ép mục tiêu bằng hai mặt đất"],"nguonGoc":"Do chín vị lão tổ Quy Nhất tông đồng thời bày ra","dacDiem":"Gồm chín biến, mỗi biến mạnh hơn biến trước","trangThai":"Bị phá, trận linh bị Vương Lâm thu","capNhatToi":"@c1635","tabs":{"tienTrinh":[{"chuong":"@c1635","loai":"dùng","importance":"major","giaiDoan":"Bị Vương Lâm phá và thu trận linh","text":"Vương Lâm đối mặt trận thứ nhất, tung chín quyền phá chín mặt người đất sơ biến, bị đệ nhị biến hai mặt đất ép chặt nhưng đấm vỡ từ bên trong, thu luôn trận linh.","anchor":"Chúng hóa thành một dúm đất! Một dúm bùn đất này tỏa ra linh khí dày đặc, chính là trận linh của Ngũ hành đại trận"}]},"nguon":["@c1635"]},{"id":"ngu-hanh-hoa-tran","name":"Ngũ Hành hỏa trận","cn":"五行火阵","loai":"bi-thuat","loaiLabel":"Trận pháp","phamCap":"Không rõ","hePhai":"Quy Nhất tông","soHuu":["Quy Nhất tông"],"blurb":"Trận pháp thuộc hệ hỏa trong Ngũ Hành đại trận của Quy Nhất tông. Bị Vương Lâm chỉ huy người khổng lồ lửa phá sập, cảnh tượng chuyển sang thủy trận.","detail":"Một trong năm trận thuộc Ngũ Hành đại trận. Bị Vương Lâm đứng trên đỉnh đầu người khổng lồ lửa chỉ huy vung tay phá nát, ầm ầm sụp đổ, cảnh tượng biến đổi chuyển sang Ngũ Hành thủy trận.","trangThai":"Bị phá","congNang":["Hỏa trận trong Ngũ Hành đại trận, có người khổng lồ lửa và chín Kỳ Lân lửa"],"tabs":{"tienTrinh":[{"chuong":"@c1637","loai":"nhắc tới","importance":"major","giaiDoan":"Bị phá sập","text":"Vương Lâm chỉ huy người khổng lồ lửa vung tay phá nát hỏa trận, cảnh tượng chuyển sang thủy trận.","anchor":"Một cái vung này liền khiến cho hỏa trận ầm ầm sụp đổ"}]},"capNhatToi":"@c1637","nguon":["@c1637"]},{"id":"ngu-hanh-thuy-tran","name":"Ngũ Hành thủy trận","cn":"五行水阵","loai":"bi-thuat","loaiLabel":"Trận pháp","phamCap":"Không rõ","hePhai":"Quy Nhất tông","soHuu":["Quy Nhất tông"],"blurb":"Trận pháp thuộc hệ thủy trong Ngũ Hành đại trận, hiện ra hải dương vô tận với sóng gió mây đen. Thủy Tướng có thân thể thủy linh hoàn chỉnh là linh hồn trận, uy lực gấp bội.","detail":"Trận tiếp theo trong Ngũ Hành đại trận của Quy Nhất tông, kích hoạt sau khi hỏa trận bị phá. Hiện ra hải dương vô tận, sóng gió, mây đen dày đặc, mưa to gào thét. Thủy Tướng có thân thể thủy linh Ngũ Hành hoàn chỉnh là linh hồn thủy trận, khiến uy lực gia tăng gấp bội. Trong trận có bốn bức tường nước vạn trượng, trường thương nước mưa huyễn hóa.","thuocTinh":"Thủy","congNang":["Thủy linh hoàn chỉnh làm linh hồn trận, uy lực gấp bội","Bốn bức tường nước vạn trượng bao vây đối thủ","Trường thương nước mưa huyễn hóa hợp nhất với thân Thủy Tướng"],"tabs":{"tienTrinh":[{"chuong":"@c1637","loai":"xuất hiện","importance":"major","giaiDoan":"Kích hoạt sau khi hỏa trận bị phá","text":"Thủy trận kích hoạt, Thủy Tướng xuất hiện là linh hồn trận, dùng bốn bức tường nước vạn trượng và trường thương nước mưa nhấn chìm Vương Lâm trong biển.","anchor":"Có hắn ở đây, uy lực thủy trận sẽ gia tăng gấp bội"}]},"capNhatToi":"@c1637","nguon":["@c1637"]},{"id":"can-khon-nhat-tich","name":"Càn Khôn Nhất Tích","cn":"乾坤一滴","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Thủy","soHuu":["Thủy Tướng"],"blurb":"Thần thông do tổ tiên Thủy Tướng truyền, dùng thân thể thủy linh ngưng tụ toàn bộ nước biển và nước mưa thành quả cầu khổng lồ rồi co rút thành một giọt chứa lực lượng thủy bổn nguyên, ép nát mọi thứ bên trong.","detail":"Người thi triển phun máu bắt quyết, dùng thân thể thủy linh ngưng tụ thủy lực Ngũ Hành, nâng toàn bộ hải dương lên trời đồng thời phá tan mây đen khiến nước mưa đổ xuống, dung hợp nước biển và nước mưa thành quả cầu nước khổng lồ bao trùm mục tiêu. Quả cầu co rút liên tục, áp lực tăng vô số lần; nếu luyện hóa hoàn toàn thành một giọt thì tinh không bên trong cũng bị ép tan — đây chính là lực lượng thủy bổn nguyên. Đại giá: tuôn hết lực lượng áo giáp, thân thể héo rũ nổi mụn mủ, lộ hình dạng thật.","thuocTinh":"Thủy","nguonGoc":"Tổ tiên Thủy Tướng truyền, theo phương pháp Quy Nhất tông trên Tiên Cương đại lục","uyLuc":"Co nén toàn bộ nước thành một giọt chứa thủy bổn nguyên, dù tinh không bên trong cũng bị ép tan","dacDiem":"Người thi triển phải tuôn hết lực lượng, thân thể suy kiệt héo rũ sau khi dùng","congNang":["Co nén toàn bộ nước thành một giọt chứa thủy bổn nguyên, ép nát mục tiêu bên trong"],"nguoiTu":[{"ten":"Thủy Tướng","tuChuong":"@c1638","tangDatToi":"","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1638","loai":"thi triển","importance":"major","giaiDoan":"Lần đầu thi triển","text":"Thủy Tướng phun máu bắt quyết, dùng thân thể thủy linh ngưng tụ toàn bộ nước biển và nước mưa thành quả cầu khổng lồ nhốt Vương Lâm, co rút ép nén. Tuôn hết lực lượng áo giáp, thân thể héo rũ lộ hình dạng thật. Tuy nhiên Vương Lâm chọn ở lại bên trong cảm ngộ thủy bổn nguyên thay vì thoát ra.","anchor":"Càn khôn nhất tích!"}]},"nguon":["@c1638"]},{"id":"cuu-chuyen-tam-luan","name":"Cửu Chuyển Tâm Luân","cn":"九轉心輪","loai":"bi-thuat","loaiLabel":"Trận pháp","phamCap":"Trận pháp hộ sơn Quy Nhất tông","hePhai":"Quy Nhất tông","soHuu":["Quy Nhất tông","Đệ Cửu lão tổ"],"blurb":"Trận pháp hộ sơn của Quy Nhất tông, kích hoạt sau khi Ngũ Hành đại trận bị phá. Dựa vào tâm bất động, mỗi chín nhịp thở là một chuyển, tâm động càng nhanh thì chuyển càng nhanh.","detail":"Cửu Chuyển Tâm Luân là trận pháp hộ sơn tối hậu của Quy Nhất tông. Nguyên lý: mỗi chín nhịp thở là một chuyển, tâm động càng nhanh thì chuyển động càng nhanh, tất cả dựa vào tâm bất động hay không. Chỉ cần đối phương không nhìn ra dấu vết ngay từ đầu, bị cuốn vào một chuyển thì nhất định không thể phá nổi. Bản tại Ngũ Hành tinh chỉ có bốn phần uy lực so với đại trận gốc đặt tại tổng đàn Quy Nhất tông trên Tiên Cương đại lục. Biểu hiện khi kích hoạt: Ngũ Hành tinh bắt đầu chuyển động.","thuocTinh":"Tâm cảnh","nguonGoc":"Quy Nhất tông sáng chế, bản gốc đặt tại Tiên Cương đại lục","dacDiem":"Dựa vào tâm bất động, mỗi chín nhịp thở một chuyển, bị cuốn vào một chuyển thì không phá nổi","uyLuc":"Bản Ngũ Hành tinh bốn phần uy lực so bản gốc Tiên Cương; đủ sức giữ chân cường giả nếu tâm dao động","congNang":["Trận pháp dựa vào tâm cảnh, tâm bất động thì phá được, tâm động thì bị cuốn không thoát","Khống chế tâm thần người bị nhốt, cứ 9 nhịp thở tăng tốc 1 chuyển, tổng 9 chuyển @c1642","Tâm động → tốc độ xoay tăng → hao tổn tâm thần → tiêu tốn thọ nguyên tử vong @c1642","Dùng Ngũ Hành tinh xoay tròn làm ảo cảnh, nhắm mắt vẫn thấy qua thần thức @c1642"],"trangThai":"Đang kích hoạt tại Ngũ Hành tinh","capNhatToi":"@c1641","tabs":{"tienTrinh":[{"chuong":"@c1641","loai":"xuat-hien","importance":"major","giaiDoan":"Kích hoạt sau khi Ngũ Hành đại trận bị phá","text":"Sau khi Vương Lâm phá xong toàn bộ Ngũ Hành đại trận, Cửu Chuyển Tâm Luân kích hoạt khiến Ngũ Hành tinh bắt đầu chuyển động. Đệ Cửu lão tổ giải thích nguyên lý: mỗi chín nhịp thở là một chuyển, tâm động càng nhanh thì chuyển càng nhanh, tất cả dựa vào tâm bất động.","anchor":"Cửu Chuyển Tâm Luân, mỗi chín nhịp thở là một chuyển, tâm động càng nhanh thì chuyển động càng nhanh"},{"chuong":"@c1642","loai":"he-lo-tang-chieu","importance":"major","giaiDoan":"Hé lộ toàn bộ cơ chế chín chuyển và bị Vương Lâm bước đầu phá giải","text":"Lão già kim bào giải thích cơ chế chín chuyển cho Nạp Đa. Vương Lâm trải qua đệ nhất tới đệ cửu chuyển, tâm thần hao tổn cực độ, phun máu. Tại đệ cửu chuyển ngộ ra bản chất tâm động, tĩnh tâm lại, chuyển động bắt đầu chậm.","anchor":"Cửu Chuyển Tâm Luân, dù là trên Tiên Cương đại lục cũng rất ít người có thể phá vỡ"}]},"nguon":["@c1641","@c1642"]},{"id":"ngu-hanh-moc-tran","name":"Ngũ Hành mộc trận","cn":"五行木陣","loai":"bi-thuat","loaiLabel":"Trận pháp","phamCap":"Một phần của Ngũ Hành Quy Nhất trận","hePhai":"Quy Nhất tông","soHuu":["Quy Nhất tông"],"blurb":"Trận thứ tư trong Ngũ Hành đại trận. Thiên địa cây cối rậm rạp, lá cây tấn công bao vây, mộc linh hóa khuôn mặt khổng lồ trên mặt đất.","detail":"Ngũ Hành mộc trận là trận thứ tư trong hệ thống Ngũ Hành đại trận của Quy Nhất tông. Bên trong là thiên địa cây cối rậm rạp, đại thụ vươn tận trời, lá cây có sợi tơ liên kết tấn công từ bốn phương bao vây. Cây cối mất lá có thể biến hóa thành khuôn mặt khổng lồ trên mặt đất — đó là mộc linh. Mộc chủ nhu hòa, cho phép đối phương chọn lựa thần phục hoặc bị hủy diệt. Bị Vương Lâm dùng thuật Tê Thiên xé thiên địa làm đôi rồi ép mộc linh quy phục.","nguon":["@c1641"]},{"id":"ngu-hanh-kim-tran","name":"Ngũ Hành kim trận","cn":"五行金陣","loai":"bi-thuat","loaiLabel":"Trận pháp","phamCap":"Một phần của Ngũ Hành Quy Nhất trận","hePhai":"Quy Nhất tông","soHuu":["Quy Nhất tông"],"blurb":"Trận cuối cùng trong Ngũ Hành đại trận. Thiên địa toàn kiếm phát kim quang, vạn kiếm đồng reo lao tới tấn công, kim cứng rắn bất hủ tuyệt không khom mình.","detail":"Ngũ Hành kim trận là trận thứ năm và cuối cùng trong hệ thống Ngũ Hành đại trận. Bên trong thiên địa toàn kiếm phát kim quang thay thế mặt đất và bầu trời, sát khí bùng lên, vạn kiếm đồng loạt reo vang lao về phía kẻ xâm nhập. Kim cứng rắn bất hủ, một đường thẳng tiến tuyệt đối không khom mình. Sau khi kim trận bị Vương Lâm phá, toàn bộ Ngũ Hành đại trận tan rã hoàn toàn.","nguon":["@c1641"]},{"id":"than-tinh-dan-tam","name":"Thân tình dẫn tâm","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"Không rõ","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Phương pháp Vương Lâm tự sáng tạo để phá Cửu Chuyển Tâm Luân: không trực tiếp tĩnh tâm mà dùng thân thể dễ tĩnh hơn làm gốc, rồi từ thân → hồn → thần → tâm lần lượt tĩnh.","detail":"Nguyên lý: khi bị trận pháp tác động tâm thần, tâm quá khó tĩnh trực tiếp, nên lấy thân làm gốc — thân tĩnh dễ hơn, từ thân tĩnh ảnh hưởng hồn phách, hồn phách tĩnh rồi kiềm chế thần, ba thứ đều tĩnh thì tâm tất tĩnh. Huyền La Đại Thiên Tôn phân tích rõ nguyên lý và đánh giá rất cao.","thuocTinh":"Tâm pháp phá trận","nguonGoc":"Vương Lâm tự ngộ trong đệ cửu chuyển Cửu Chuyển Tâm Luân","dacDiem":"Lấy thân dẫn động, lấy hồn phách làm gốc kiềm chế tâm thần","congNang":["Phá trận pháp tác động tâm thần bằng cách tĩnh tâm gián tiếp qua thân-hồn-thần"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1643","tangDatToi":"","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c1643","loai":"xuất hiện","importance":"major","giaiDoan":"Vương Lâm sáng tạo và sử dụng lần đầu","text":"Vương Lâm ngộ ra phương pháp thân tình dẫn tâm trong đệ cửu chuyển Cửu Chuyển Tâm Luân, dùng chín nhịp thở phá hoàn toàn trận pháp. Huyền La Đại Thiên Tôn quan sát và phân tích chính xác nguyên lý.","anchor":"lấy thân dẫn động, lấy thân rời xa đi. Thân là hình, tĩnh dễ dàng hơn"}]},"nguon":["@c1643"]},{"id":"nghich-chuyen-cuu-chuyen-tam-luan","name":"Nghịch chuyển Cửu Chuyển Tâm Luân","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"Không rõ","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Ứng dụng chiến đấu: Vương Lâm dùng nguyên lý tâm động thì tinh động, vẽ vòng tròn ngược chiều kim đồng hồ nghịch chuyển Ngũ Hành tinh, đảo ngược Cửu Chuyển Tâm Luân đánh vào chính tu sĩ Quy Nhất tông.","detail":"Sau khi phá Cửu Chuyển Tâm Luân, Vương Lâm không rời trận mà lợi dụng nguyên lý cốt lõi của trận: tâm động thì tinh động. Hắn chủ ý nghịch động tâm, vẽ vòng tròn ngược khiến Ngũ Hành tinh nghịch chuyển, đảo ngược toàn bộ trận pháp hướng vào tu sĩ trên Ngũ Hành tinh.","congNang":["Đảo ngược Cửu Chuyển Tâm Luân đánh vào phía bày trận"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1643","tangDatToi":"","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c1643","loai":"thi triển","importance":"major","giaiDoan":"Lần đầu sử dụng","text":"Vương Lâm nghịch chuyển Cửu Chuyển Tâm Luân đánh ngược tu sĩ Quy Nhất tông, khiến đa số hôn mê ở đệ tứ chuyển, lão già kim bào chống tới đệ thất chuyển.","anchor":"Tâm động thì tinh động. Giờ phút này tâm ta nghịch động, dẫn chuyển tu chân tinh này nghịch chuyển"}]},"nguon":["@c1643"]},{"id":"luc-hoa-an","name":"Lục Hoa Ấn","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Quy Nhất tông","soHuu":["Vân Dật Phong"],"blurb":"Ấn quyết triệu sáu đóa hoa khổng lồ màu đen, từ mỗi đóa hoa thò ra một cánh tay trắng muốt đánh ra. Lực hủy diệt cực mạnh, khi vỡ tán để lại tà khí khắc lên cơ thể đối thủ gây rữa nát chảy mủ.","detail":"Vân Dật Phong bắt quyết điểm ra một ấn, triệu sáu đóa hoa khổng lồ màu đen tỏa u quang. Từ mỗi đóa hoa thò ra một cánh tay trắng muốt đánh ra, va chạm ngang sức với quyền của Vương Lâm cảnh Đạo Hư. Khi sáu đóa hoa vỡ tán, để lại sáu đóa hoa đen khắc trên cánh tay đối thủ gây rữa nát chảy mủ — cần Đạo Cổ bất diệt thể hoặc đan dược đặc biệt mới hóa giải.","congNang":["Triệu 6 đóa hoa đen khổng lồ + 6 cánh tay trắng muốt tấn công","Tà khí hoa đen khắc lên cơ thể đối thủ gây rữa nát chảy mủ"],"tabs":{"tienTrinh":[{"chuong":"@c1644","loai":"thi triển","importance":"normal","giaiDoan":"Vân Dật Phong thi triển lần đầu","text":"Vân Dật Phong dùng Lục Hoa Ấn giao chiến ngang sức Vương Lâm, sáu đóa hoa đen khắc lên cánh tay phải Vương Lâm gây rữa nát.","anchor":"sáu đóa hoa khổng lồ màu đen. Sáu đóa hoa này lập tức tỏa ra u quang"}]},"nguon":["@c1644"]},{"id":"dao-co-bat-diet-the","name":"Đạo Cổ bất diệt thể","cn":"","loai":"luyen-the","loaiLabel":"Luyện thể","phamCap":"Không rõ","hePhai":"Đạo cổ nhất mạch","soHuu":["Vương Lâm"],"blurb":"Thể chất đặc biệt thuộc Đạo Cổ nhất mạch, có lực lượng khôi phục cực mạnh, có thể tự hóa giải tà thuật và thương tổn ngoại lai.","detail":"Đạo Cổ bất diệt thể cho phép Vương Lâm tự động khôi phục thương tổn ngoại lai. Tại Ngũ Hành tinh, sáu đóa hoa đen từ Lục Hoa Ấn của Vân Dật Phong khắc lên cánh tay phải gây rữa nát — dưới lực lượng khôi phục của bất diệt thể liền tan nát, tốc độ nhanh hơn so với dùng đan dược vài nhịp thở.","congNang":["Tự hóa giải tà thuật và thương tổn ngoại lai trên cơ thể","Tốc độ khôi phục nhanh hơn đan dược đặc biệt"],"tabs":{"tienTrinh":[{"chuong":"@c1644","loai":"thi triển","importance":"normal","giaiDoan":"Khôi phục nhanh hơn đan dược","text":"Vương Lâm dùng bất diệt thể đánh tan sáu đóa hoa đen trên cánh tay phải, khôi phục nhanh hơn Vân Dật Phong dùng đan dược vài nhịp thở.","anchor":"dưới lực lượng khôi phục của Đạo cổ bất diệt thể của Vương Lâm liền tan nát"}]},"nguon":["@c1644"]},{"id":"mat-quy-nhap-huyen","name":"Mặt quỷ nhập huyễn, mộng ảo ngàn năm","aliases":["Mặt quỷ nhập huyễn"],"loai":"than-thong","loaiLabel":"Thần thông","hePhai":"Mộng ảo","soHuu":["Vương Lâm"],"blurb":"Thần thông mộng ảo do Vương Lâm thi triển, kết hợp tấm buồm mặt quỷ (Cấm Phiên) và tiếp xúc mi tâm đối tượng để đưa thần thức vào thế giới mộng ảo tái hiện ký ức quá khứ.","detail":"Vương Lâm đặt tay phải lên mi tâm mình, tay trái lên mi tâm Lý Mộ Uyển, niệm chú. Tấm buồm mặt quỷ biến ảo, mặt quỷ gào thét vô thanh rồi lao vào mi tâm Vương Lâm, sương mù dày đặc bao phủ toàn thân. Hiệu quả: tạo thế giới mộng ảo có thể tái hiện cảnh tượng quá khứ, ở đây tái hiện lần gặp Lý Mộ Uyển đầu tiên hơn hai ngàn năm trước ở hải ngoại. Điều kiện: cần kết hợp tấm buồm mặt quỷ (Cấm Phiên) và tiếp xúc mi tâm đối tượng.","thuocTinh":"Mộng ảo / Ký ức","dacDiem":"Cần tấm buồm mặt quỷ (Cấm Phiên) làm môi giới, tiếp xúc mi tâm đối tượng, niệm chú kích hoạt","congNang":["Đưa thần thức vào thế giới mộng ảo tái hiện ký ức quá khứ"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1648","trangThai":"thi triển"}],"tabs":{"tienTrinh":[{"chuong":"@c1648","loai":"xuất hiện","importance":"major","giaiDoan":"Lần đầu xuất hiện","text":"Vương Lâm thi triển lần đầu, dùng tấm buồm mặt quỷ kết hợp tiếp xúc mi tâm Lý Mộ Uyển để nhập mộng ảo tái hiện lần gặp gỡ đầu tiên hơn hai ngàn năm trước.","anchor":"Mặt quỷ nhập huyễn, mộng ảo ngàn năm"}]},"nguon":["@c1648"]},{"id":"tam-hon-that-phach","name":"Tam hồn thất phách","cn":"三魂七魄","loai":"khac","loaiLabel":"Hệ thống","phamCap":"Không rõ","hePhai":"Thất Thải Tiên Tôn","soHuu":["Thất Thải Tiên Tôn"],"blurb":"Hệ thống tam hồn thất phách của Thất Thải Tiên Tôn, mỗi hồn phách chuyển thế thành một nhân vật riêng biệt. Bốn phách đã xảy ra biến số trở thành thân thể độc lập, hai phách chưa hoàn toàn tách biệt.","detail":"Sáu phách đã biết: Thanh Thủy, Tư Đồ Nam, Tham Lang, Thanh Lâm, Mộc Băng Mi, Tán Linh thượng nhân. Hồn thứ ba là Tạ Thanh. Phách thứ bảy bị Thiên Vận Tử nuốt nhưng không còn trong thiên đạo hiện tại. Bốn phách (Tham Lang, Thanh Lâm, Mộc Băng Mi, Tán Linh) đã qua nhiều lần luân hồi xảy ra biến số thiên đạo, trở thành thân thể chính thức hoàn toàn tách biệt khỏi Thất Thải Tiên Tôn. Hai phách (Thanh Thủy, Tư Đồ Nam) chưa xảy ra biến số, chưa hoàn toàn độc lập. Nếu nắm được lực lượng biến số trong thiên đạo có thể khiến hồn thứ ba độc lập, ngăn tam hồn dung hợp.","congNang":["Mỗi hồn phách chuyển thế thành nhân vật riêng biệt qua luân hồi","Biến số thiên đạo có thể biến phách thành thân thể độc lập hoàn toàn tách biệt bản thể"],"tabs":{"tienTrinh":[{"chuong":"@c1653","loai":"hé lộ tầng-chiêu","importance":"major","giaiDoan":"Giác ngộ biến số thiên đạo","text":"Vương Lâm được Huyền La điểm chỉ, nhận ra bốn phách đã qua luân hồi xảy ra biến số trở thành thân thể độc lập. Xác nhận hồn thứ ba là Tạ Thanh. Phách thứ bảy không còn trong thiên đạo.","anchor":"bốn người bọn họ trở thành thân thể chính thức, hoàn toàn không giống với Thất Thải Tiên Tôn"}]},"nguon":["@c1653"]},{"id":"khong-diet-khi","name":"Không Diệt khí","cn":"不灭气","loai":"than-thong","loaiLabel":"Thần thông / Khí tức","phamCap":"Không rõ (vượt tầm hiểu biết Đại Thiên Tôn)","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Khí tức Không Diệt lần đầu sơ hiện khi Vương Lâm phẫn nộ thề diệt trời, toàn thân bộc phát khí thế ngưng tụ thành thanh kiếm hư ảo mang uy lực phá thiên không. Huyền La Đại Thiên Tôn kinh hãi nhận ra.","detail":"Sinh ra từ lời thề của Vương Lâm khi cực độ phẫn nộ — thề cả đời muốn diệt trời. Lời thề huyễn hóa thành khí tức Không Diệt, ngưng tụ thành thanh kiếm hư ảo có khí tức như muốn phá tan thiên không. Huyền La Đại Thiên Tôn lần đầu đại biến sắc mặt, vô cùng khiếp sợ trước khí tức này.","congNang":["Bộc phát thành thanh kiếm hư ảo có khí tức phá thiên không"],"dacDiem":"Sinh ra từ lời thề cực độ phẫn nộ, vượt tầm hiểu biết của Đại Thiên Tôn","nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1654","tangDatToi":"Sơ hiện","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1654","loai":"xuat-hien","importance":"major","giaiDoan":"Sơ hiện","text":"Vương Lâm phẫn nộ thề diệt trời, toàn thân bộc phát khí thế ngưng tụ thành thanh kiếm hư ảo mang khí tức Không Diệt. Huyền La Đại Thiên Tôn kinh hãi nhận ra, cho rằng lời thề đã huyễn hóa ra khí tức này.","anchor":"Lời thề của người này không ngờ lại có thể huyễn hóa ra khí tức của Không Diệt"}]},"nguon":["@c1654"]},{"id":"ba-dao-phong-an-ta-thanh","name":"Ba đạo phong ấn của Tạ Thanh","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật / Phong ấn","phamCap":"Không rõ","hePhai":"","soHuu":["Tạ Thanh"],"blurb":"Ba đạo phong ấn Tạ Thanh dùng hồn tu lực ngưng tụ nhiều năm: chặn luân hồi hồn thứ ba, mở trung tâm động phủ và đại môn rời động phủ giới, phối hợp lực Tiên Cương phong ấn hồn thứ nhất và hồn thứ hai.","detail":"Phong ấn thứ nhất: tự thân dẫn động, khi Tạ Thanh chết hồn thứ ba không thể luân hồi để Vương Lâm thu lấy; hồn thứ ba thức tỉnh hoàn toàn sẽ mở trung tâm động phủ, mở đại môn rời động phủ giới. Hai phong ấn còn lại: phối hợp lực lượng từ Tiên Cương đại lục khi mở đại môn, giúp Vương Lâm phong ấn hồn thứ nhất và hồn thứ hai. Tạ Thanh tâm hồn hao tổn cực độ vì ba đạo phong ấn.","congNang":["Chặn luân hồi hồn thứ ba khi Tạ Thanh chết","Mở trung tâm động phủ và đại môn thông Tiên Cương đại lục","Phối hợp lực Tiên Cương phong ấn hồn thứ nhất và hồn thứ hai"],"nguoiTu":[{"ten":"Tạ Thanh","tuChuong":"@c1654","tangDatToi":"Hoàn thành","trangThai":"da-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c1654","loai":"thi-trien","importance":"major","giaiDoan":"Hoàn thành và kích hoạt","text":"Tạ Thanh dùng hồn tu lực nhiều năm ngưng tụ ba đạo phong ấn. Phong ấn thứ nhất tự thân dẫn động khi chết. Tạ Thanh khí tuyệt thân vong, phong ấn kích hoạt — hồn thứ ba không luân hồi, Vương Lâm thu lấy.","anchor":"Những năm gần đây, sau khi hồn thứ ba thức tỉnh, ta lấy hồn tu lực, ngưng tụ ba đạo phong ấn"}]},"nguon":["@c1654"]},{"id":"dinh-quy-tac-tan-gioi","name":"Định quy tắc tàn giới","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Năng lực đặc biệt cho phép truyền thần niệm để định ra quy tắc cho tàn giới loại ba (không sinh linh), đòi hỏi huyết mạch tiên nhân.","detail":"Vương Lâm thử truyền thần niệm vào ngọn núi trọc trong tàn giới loại ba để định quy tắc. Thiên địa ầm vang, tinh vực vặn vẹo kịch liệt, quy tắc mơ hồ sinh ra nhưng bị đè nén vì tàn giới không đủ lực ngưng tụ. Điều kiện tiên quyết là cần huyết mạch tiên nhân.","thuocTinh":"Quy tắc","nguonGoc":"Năng lực vốn có của tàn giới loại ba, người đầu tiên tới có thể định quy tắc","yeuCau":"Huyết mạch tiên nhân, tàn giới đủ lực lượng","congNang":["Thay đổi pháp tắc trong tàn giới loại ba (không sinh linh)"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1658","tangDatToi":"","trangThai":"thử nghiệm thất bại lần đầu"}],"tabs":{"tienTrinh":[{"chuong":"@c1658","loai":"thi triển","importance":"normal","giaiDoan":"Thử nghiệm lần đầu","text":"Vương Lâm truyền thần niệm vào ngọn núi trọc trên tu chân tinh thứ năm, thiên địa ầm vang, quy tắc mơ hồ sinh ra nhưng bị đè nén vì tàn giới không đủ lực ngưng tụ.","anchor":"cấm chế quy tắc này đều phải cần tới huyết mạch tiên nhân"}]},"nguon":["@c1658"]},{"id":"quy-tac-cam-phi-hanh","name":"Quy tắc cấm phi hành","cn":null,"loai":"bi-thuat","loaiLabel":"Quy tắc tàn giới","phamCap":"Quy tắc duy nhất ngưng tụ hoàn chỉnh trong tàn giới","hePhai":null,"soHuu":["Vương Lâm"],"blurb":"Quy tắc do Vương Lâm thiết lập trong tàn giới, khiến đối phương mất năng lực phi hành và rơi xuống nhanh.","detail":"Quy tắc duy nhất mà Vương Lâm có thể ngưng tụ hoàn chỉnh trong tàn giới của mình. Hiệu quả khiến mọi kẻ bước vào tàn giới mất năng lực phi hành, phải rơi xuống. Tuy nhiên có giới hạn thời gian tùy theo tu vi đối phương — tu vi càng cao thì thời gian bị ảnh hưởng càng ngắn. Ngoài ra quy tắc này không ảnh hưởng tới pháp bảo, đối phương vẫn có thể dùng pháp bảo nâng thân. Trận pháp cấm chế đi kèm chỉ đủ sức giết được ba người, sau đó mất hiệu lực sát thương. Vương Lâm dùng quy tắc này phục kích giết tổng cộng bốn đệ tử Thất Đạo Tông: lão già viễn cổ tiên nhân ngày đầu bị mất phi hành rồi bị huyết kiếm xuyên mi tâm; ba tiên nhân ngày thứ sáu (một Không Niết sơ kỳ, hai thiên nhân ngũ suy) cũng bị cấm phi hành rồi bị giết trong chưa tới ba nhịp thở.","nguon":["@c1659"]},{"id":"phong-an-chin-chi","name":"Phong ấn chín chỉ","cn":"","loai":"bi-thuat","loaiLabel":"Cấm chế","phamCap":"","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Vương Lâm điểm chín chỉ lên người đối phương, mỗi chỉ đưa vào một luồng lực lượng phong ấn, tạo cấm chế hư ảo như mạng nhện tràn ngập toàn thân, phong ấn đại thành.","detail":"Cấm chế phong ấn cực mạnh. Vương Lâm điểm chín chỉ liên tiếp, mỗi chỉ mang một luồng lực lượng phong ấn tạo thành mạng cấm chế hư ảo bao phủ toàn thân đối phương, đạt phong ấn đại thành. Dùng kết hợp sau Định thân thuật để hoàn toàn khống chế đối thủ.","congNang":["Phong ấn hoàn toàn đối phương sau khi đã bị Định thân thuật cố định"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1661","tangDatToi":"","trangThai":"dang-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c1661","loai":"thi triển","importance":"major","giaiDoan":"Lần đầu xuất hiện","text":"Vương Lâm điểm chín chỉ lên người Tử Hà tạo cấm chế phong ấn đại thành, thu nàng vào tay áo.","anchor":"Chín chỉ này điểm xuống, phong ấn đại thành!"}]},"nguon":["@c1661"]},{"id":"quy-tac-tan-gioi-bach-ho","name":"Quy tắc tàn giới (Bạch Hổ chiến tướng)","cn":"","loai":"khac","loaiLabel":"Quy tắc","phamCap":"","hePhai":"","soHuu":["Bạch Hổ"],"blurb":"Người đầu tiên bước vào tàn giới có thể định ra tất cả quy tắc, những người đến sau đều phải tuân theo.","detail":"Quy tắc đặc thù của tàn giới: ai vào trước thì định ra toàn bộ luật lệ, người đến sau bị ràng buộc. Bạch Hổ chiến tướng thiết lập quy tắc khiến người vào phải hư ảo hóa và liên kết với binh tướng thế tục để chiến đấu. Chỉ đạo nhân bảy màu (Thất Thải Tiên Tôn) hoặc Chiến lão quỷ mới thoát khỏi. Vương Lâm đứng yên không bước vào để giữ mình ngoài quy tắc.","congNang":["Ràng buộc mọi người đến sau vào quy tắc do người đến trước đặt ra","Hư ảo hóa và liên kết với binh tướng thế tục"],"tabs":{"tienTrinh":[{"chuong":"@c1661","loai":"xuất hiện","importance":"major","giaiDoan":"Bạch Hổ thiết lập","text":"Bạch Hổ chiến tướng là người đầu tiên vào tàn giới, đã thiết lập toàn bộ quy tắc, tự tin chỉ đạo nhân bảy màu hoặc Chiến lão quỷ mới thoát.","anchor":"tất cả các quy tắc ở đây đều do ta định ra!"}]},"nguon":["@c1661"]},{"id":"thon-hon","name":"Thôn Hồn","cn":"吞魂","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Bản năng thôn hồn của thần thức Vương Lâm, có thể nuốt hồn phách và thần thức đối phương. Hoạt động ngay cả khi bị quy tắc giới áp chế.","detail":"Thần thức Vương Lâm mang bản năng thôn hồn, dùng để nuốt trọn phân thân đối phương đã suy yếu trong giới cờ, gia tăng mạnh lực lượng bản thân.","congNang":["Nuốt hồn phách và thần thức đối phương, chuyển hóa thành lực lượng bản thân","Bản năng thôn hồn hoạt động ngay cả khi bị quy tắc giới áp chế"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1663","tangDatToi":"","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1663","loai":"thi triển","importance":"normal","giaiDoan":"Sử dụng trong giới cờ","text":"Thần thức Vương Lâm dùng bản năng thôn hồn nuốt trọn chiến tướng kim giáp (tu sĩ Ngũ Hành tinh) đã suy yếu, gia tăng mạnh lực lượng quân cờ.","anchor":"hắn là thôn hồn, thần thức của hắn cũng có năng lực này"}]},"nguon":["@c1663"]},{"id":"that-thai-dao-lien","name":"Thất Thải Đạo Liên","cn":"七彩道莲","aliases":["đài sen bảy màu"],"loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Không rõ","soHuu":["Đạo nhân bảy màu"],"blurb":"Thần thông của Đạo nhân bảy màu, triệu hoa sen bảy cánh bảy màu có thể co rút thành nụ hoa phòng ngự hoặc nở ra phản công, uy lực cực mạnh.","detail":"Đạo nhân bảy màu triệu hoa sen bảy cánh bảy màu, hô khẩu quyết khiến nụ hoa co rút bao phủ thân phòng ngự hoặc nở cánh phóng ra tấn công. Khi phòng ngự chịu được đường đao chứa lực lượng cả một giới nhưng bị vỡ hai cánh. Năm cánh còn lại nở ra dùng phản công.","congNang":["Phòng ngự: co rút thành nụ hoa bao phủ thân, chịu đòn cực mạnh","Phản công: nở cánh phóng ra tấn công đối thủ"],"uyLuc":"Chịu được đường đao mượn quy tắc cả một giới nhưng mất hai cánh","dacDiem":"Bảy cánh bảy màu, có khẩu quyết khai/hợp","nguoiTu":[{"ten":"Đạo nhân bảy màu","tuChuong":"@c1664","tangDatToi":"Không rõ","trangThai":"dang-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c1664","loai":"thi triển","importance":"major","giaiDoan":"Lần đầu xuất hiện","text":"Đạo nhân bảy màu triệu Thất Thải Đạo Liên phòng ngự đường đao mượn lực cả giới của Vương Lâm, bị vỡ hai cánh hoa. Sau đó nở năm cánh còn lại phản công.","anchor":"Thất thải đạo liên, liên ngưng binh tu"}]},"nguon":["@c1664"]},{"id":"tam-menh-thuat","name":"Tam mệnh thuật","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Thần thông phản kích mạnh mẽ, Vương Lâm quyết định dùng để cho kẻ truy kích bài học khó quên, mỗi lần sử dụng tiêu hao một lần cơ hội.","detail":"Vương Lâm quyết định sử dụng Tam mệnh thuật để phản kích những kẻ truy kích sau khi thoát thân. Hắn coi việc tiêu hao một lần sử dụng là đáng giá, cho thấy thần thông này có số lần dùng giới hạn và uy lực rất lớn. Bắt quyết áp tay lên mặt đất bắt đầu chuẩn bị.","congNang":["Phản kích mạnh, khiến đối phương gặp giáo huấn khó quên; số lần sử dụng có giới hạn"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1665","tangDatToi":"","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1665","loai":"xuất hiện","importance":"normal","giaiDoan":"Lần đầu đề cập, chuẩn bị thi triển","text":"Vương Lâm quyết định dùng Tam mệnh thuật phản kích kẻ truy kích, sẵn sàng tiêu hao một lần sử dụng, bắt quyết áp tay lên mặt đất bắt đầu chuẩn bị.","anchor":"tam mệnh thuật. Dù là phải dùng một lần ở đây thì ta cũng phải khiến những kẻ đuổi theo gặp phải lần giáo huấn khó quên"}]},"nguon":["@c1665"]},{"id":"that-thai-dao-thuong","name":"Thất Thải Đạo Thương","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Thần thông ngưng tụ ánh sáng bảy màu thành thanh trường thương khí tức kinh thiên, giống hệt thần thông của đạo nhân bảy màu.","detail":"Vương Lâm thi triển ánh sáng bảy màu ngưng tụ thành thanh trường thương bảy màu tỏa khí tức kinh thiên, cắm xuống mặt đất làm tầng mai phục thứ hai. Hình thức giống hệt thần thông của đạo nhân bảy màu.","congNang":["Ngưng tụ ánh sáng bảy màu thành trường thương khí tức kinh thiên"],"dacDiem":"Giống hệt thần thông của đạo nhân bảy màu","tabs":{"tienTrinh":[{"chuong":"@c1666","loai":"thi triển","importance":"normal","giaiDoan":"Vương Lâm dùng làm tầng mai phục thứ hai","text":"Vương Lâm thi triển ánh sáng bảy màu ngưng tụ thành trường thương bảy màu cắm xuống mặt đất trước mặt, tạo tầng mai phục thứ hai trên tu chân tinh.","anchor":"Ánh sáng bảy màu này nhìn lại giống hệt thần thông của đạo nhân bảy màu"}]},"nguon":["@c1666"]},{"id":"quy-kiem-huyet-pham","name":"Quỷ Kiếm Huyết Phàm","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Ảo thuật/thần thông tạo đám sương mù đỏ hóa thành mặt quỷ khổng lồ nuốt đối phương, gây mê man, có thể vây khốn cường giả trong thời gian ngắn.","detail":"Đệ tứ phục trong phục sát trận của Vương Lâm. Tạo đám sương mù đỏ như máu hóa thành mặt quỷ nuốt lấy mục tiêu, khiến đối phương lập tức mê man khoanh chân ngồi không cử động. Chiến lão quỷ không thoát được, đạo nhân bảy màu cũng bị vây khốn trong thời gian ngắn.","congNang":["Sương mù đỏ hóa mặt quỷ nuốt đối phương gây mê man, vây khốn"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1668","tangDatToi":"","trangThai":"dang-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c1668","loai":"thi triển","importance":"major","giaiDoan":"Lần đầu xuất hiện","text":"Vương Lâm tung đệ tứ phục, sương mù đỏ hóa mặt quỷ nuốt Chiến lão quỷ khiến hắn mê man bất động.","anchor":"ở phía trước Chiến lão quỷ xuất hiện một đám sương mù đỏ như máu"}]},"nguon":["@c1668"]},{"id":"mat-thuat-bach-ho","name":"Mật thuật Bạch Hổ","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"","hePhai":"Bạch Hổ","soHuu":["Vương Lâm"],"blurb":"Bí thuật của Bạch Hổ, truyền lực chấn động sâu vào lòng đất, có thể kích hoạt sinh vật đang ngủ say bên dưới.","detail":"Đệ lục phục trong phục sát trận của Vương Lâm. Vỗ tay lên mặt đất, kết hợp mật thuật Bạch Hổ và phương pháp thao túng lực lượng học từ đệ nhị Chu Tước, chấn động nhập sâu lòng đất kích thích Mục Ngư biến dị thức tỉnh.","congNang":["Truyền lực chấn động sâu vào lòng đất kích hoạt sinh vật ngủ say"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1668","tangDatToi":"","trangThai":"dang-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c1668","loai":"thi triển","importance":"major","giaiDoan":"Lần đầu xuất hiện","text":"Vương Lâm vỗ tay lên mặt đất dùng mật thuật Bạch Hổ kết hợp phương pháp thao túng lực lượng đệ nhị Chu Tước kích thích Mục Ngư biến dị thức tỉnh.","anchor":"tay trái hắn vỗ lên mặt đất mật thuật của Bạch Hổ, phương pháp thao túng lực lượng mà hắn học được từ đệ nhị Chu Tước"}]},"nguon":["@c1668"]},{"id":"luc-bat-son-he","name":"Lục bạt sơn hề","cn":"力拔山兮","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"","soHuu":["Đạo nhân bảy màu"],"blurb":"Thần thông của đạo nhân bảy màu, triệu hoán cánh tay bảy màu khổng lồ từ không trung, có thể túm bắt và ném mãnh thú cỡ lớn.","detail":"Khi thi triển, hai tay bấm quyết, tay phải chỉ lên bầu trời, triệu hoán một cánh tay bảy màu khổng lồ từ trong màn u ám trên không. Cánh tay này có sức mạnh kinh khủng, túm lấy con Mục Ngư dài mấy ngàn trượng lôi ra khỏi lòng đất rồi ném xuống mặt đất đằng xa, khiến tu chân tinh nứt vỡ và Mục Ngư trọng thương.","congNang":["Triệu hoán cánh tay bảy màu khổng lồ từ không trung, túm bắt/ném mãnh thú cỡ lớn"],"nguoiTu":[{"ten":"Đạo nhân bảy màu","tuChuong":"@c1669","tangDatToi":"","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1669","loai":"thi triển","importance":"normal","giaiDoan":"Lần đầu xuất hiện","text":"Đạo nhân bảy màu thi triển Lục bạt sơn hề triệu hoán cánh tay bảy màu khổng lồ, túm lấy Mục Ngư thứ nhất lôi khỏi lòng đất ném xa khiến nó trọng thương, tu chân tinh nứt vỡ.","anchor":"hai tay bấm quyết, tay phải bỗng nhiên chỉ lên bầu trời. -Lục bạt sơn hề!"}]},"nguon":["@c1669"]},{"id":"thien-phu-than-thong-muc-ngu","name":"Thiên phú thần thông Mục Ngư (mở mắt biến hóa)","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"","soHuu":["Mục Ngư"],"blurb":"Thiên phú thần thông của loài Mục Ngư khi mở mắt, có thể biến hóa thành bất cứ thứ gì và có được một phần uy lực của vật đó.","detail":"Loài thú Mục Ngư một khi mở hai mắt thì phát động thiên phú biến hóa, có thể biến thành bất kỳ vật gì và đạt được một phần uy lực của vật đó. Rất hiếm khi Mục Ngư mở mắt, là kỳ tích hiếm thấy. Tám con Mục Ngư từng mở mắt biến hóa thành tám mũi tên giống y hệt mũi tên Lý Quảng cả hình dáng lẫn khí tức.","congNang":["Mở mắt biến hóa thành bất kỳ vật gì, có được một phần uy lực của vật đó"],"dacDiem":"Rất hiếm khi Mục Ngư mở mắt, là kỳ tích hiếm thấy. Huyền La Đại Thiên Tôn là người duy nhất biết thần thông này.","tabs":{"tienTrinh":[{"chuong":"@c1670","loai":"thi triển","importance":"major","giaiDoan":"Tám con Mục Ngư mở mắt biến hóa","text":"Tám con Mục Ngư mở mắt phát động thiên phú biến hóa thành tám mũi tên Lý Quảng giống y hệt nguyên bản. Sau khi hào quang bảy màu sụp đổ, tám con quay về hình dạng gốc, đồng loạt hấp hối.","anchor":"loài thú Mục Ngư này một khi mở hai mắt thì có thể biến hóa thành bất cứ thứ gì, còn có được một phần uy lực của vật đó"}]},"nguon":["@c1670"]},{"id":"chin-mat-troi-than-thong","name":"Chín mặt trời (thần thông đạo nhân bảy màu)","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"","soHuu":["Đạo nhân bảy màu"],"blurb":"Thần thông mạnh nhất của đạo nhân bảy màu, triệu xuất chín mặt trời chói lọi bộc phát hào quang vạn trượng, nổ tung tạo sức mạnh hủy diệt thiên địa.","detail":"Thần thông mạnh nhất của đạo nhân bảy màu. Xuất hiện chín mặt trời chói lọi bên ngoài thân thể, bộc phát hào quang vạn trượng. Khi nổ tung tạo sức mạnh hủy diệt kinh thiên, đủ sức phá hủy ba trăm tàn giới và giết Thanh Long chiến tướng.","congNang":["Triệu xuất chín mặt trời tấn công, nổ tung tạo sức mạnh hủy diệt thiên địa"],"tabs":{"tienTrinh":[{"chuong":"@c1670","loai":"thi triển","importance":"major","giaiDoan":"Đạo nhân bảy màu thi triển chín mặt trời đối kháng tiễn thứ ba","text":"Đạo nhân bảy màu bộc phát toàn bộ tu vi thi triển chín mặt trời chói lọi. Chín mặt trời va chạm tiễn thứ ba của Vương Lâm nổ tung, tạo sức mạnh hủy diệt phá hủy ba trăm tàn giới, giết Thanh Long chiến tướng.","anchor":"Chín mặt trời này là thần thông mạnh nhất của đạo nhân bảy màu"}]},"nguon":["@c1670"]},{"id":"ngu-hoa-bat-mon","name":"Ngũ hoa bát môn","cn":"五花八門","loai":"bi-thuat","loaiLabel":"Trận pháp / Hệ thống phòng hộ","phamCap":"Không rõ","hePhai":"Thất Thải Tiên Tôn","soHuu":["Thất Thải Tiên Tôn"],"blurb":"Hệ thống phòng hộ nhiều tầng tại trung tâm động phủ Thất Thải Tiên Tôn, gồm năm đóa hoa và bát môn (bảy giả một thật), cửa thật thông tới Tiên Cương đại lục.","detail":"Đệ nhất hoa là ba trăm tàn giới (đã sụp đổ). Đệ nhị hoa là thế giới đóng băng tái hiện Đông Lâm tông. Bát môn ẩn trong đóa hoa cuối cùng, bảy giả một thật, cửa thật thông tới Tiên Cương đại lục. Đệ ngũ hoa là phong ấn của Thất Thải Tiên Tôn đối với cánh cửa đó.","congNang":["Phòng hộ nhiều tầng bảo vệ lối vào Tiên Cương đại lục","Bát môn bảy giả một thật ngăn cản xâm nhập"],"nguonGoc":"Do Thất Thải Tiên Tôn tạo ra","dacDiem":"Năm đóa hoa, bát môn bảy giả một thật","tabs":{"tienTrinh":[{"chuong":"@c1671","loai":"he-lo-tang-chieu","importance":"major","giaiDoan":"Lộ cấu trúc toàn bộ hệ thống","text":"Vương Lâm sau khi rời ba trăm tàn giới (đệ nhất hoa đã sụp đổ) tiến vào đệ nhị hoa — thế giới đóng băng. Cấu trúc Ngũ hoa bát môn được hé lộ: năm đóa hoa, bát môn bảy giả một thật, cửa thật thông Tiên Cương đại lục, đệ ngũ hoa là phong ấn.","anchor":"Ngũ hoa bát môn, đây chính là tên của vòng phòng hộ trong trung tâm động phủ của Thất Thải Tiên Tôn"}]},"nguon":["@c1671"]},{"id":"tran-phap-dong-bang-dong-phu-gioi","name":"Trận pháp đóng băng (chủ nhân động phủ giới)","cn":"","loai":"khac","loaiLabel":"Trận pháp","phamCap":"Không rõ","hePhai":"Đạo cổ nhất mạch","soHuu":["Vương Lâm"],"blurb":"Trận pháp trong động phủ giới Diệp Mịch, người đầu tiên tiến vào là chủ nhân, có thể kích hoạt biến thiên địa thành kết giới đóng băng phong bế mọi kẻ xâm nhập.","detail":"Nữ Cổ Thần giải thích người đầu tiên tiến vào nơi này là chủ nhân, có thể kích hoạt trận pháp biến toàn bộ thiên địa thành khối băng ngăn cản tất cả mọi người bước vào. Tuy nhiên, kẻ tu vi quá cao mang khí tức chủ nhân thì tầng băng không giữ được lâu.","congNang":["Phong bế toàn bộ thiên địa thành khối băng, phong ấn mọi kẻ xâm nhập"],"nguon":["@c1672"]},{"id":"dao-co-bat-diet-chi","name":"Đạo Cổ bất diệt chỉ","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"Đạo Cổ","soHuu":["Vương Lâm"],"blurb":"Thần thông ngưng tụ Đạo Cổ lực trên năm ngón tay, xuất hiện ngàn vạn tàn ảnh rồi hợp nhất chụp xuống, uy lực cực mạnh.","detail":"Vương Lâm thi triển: Đạo Cổ lực trong cơ thể ầm ầm chuyển động, toàn bộ ngưng tụ trên năm ngón tay phải, xuất hiện ngàn vạn tàn ảnh rồi hợp nhất chụp xuống. Dùng liên tục suốt mấy canh giờ phá tầng băng Đông Lâm Trì có lực tự phục hồi do dung hợp với cánh tay trái Diệp Mịch, giật tung nhiều khối băng lớn, tạo hố sâu bốn trượng.","congNang":["Ngưng tụ Đạo Cổ lực trên năm ngón tay, tạo ngàn vạn tàn ảnh hợp nhất chụp xuống phá phong ấn/tầng băng"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1673","tangDatToi":"","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1673","loai":"thi triển","importance":"normal","giaiDoan":"Phá băng Đông Lâm Trì","text":"Vương Lâm thi triển Đạo Cổ bất diệt chỉ phá tầng băng Đông Lâm Trì có lực tự phục hồi, liên tục sử dụng suốt mấy canh giờ, giật tung nhiều khối băng lớn để lộ cánh tay trái Diệp Mịch.","anchor":"Đạo cổ lực trong cơ thể hắn ầm ầm chuyển động, toàn bộ ngưng tụ trên năm ngón tay phải"}]},"nguon":["@c1673"]},{"id":"that-dieu-kim-mon","name":"Thất Diện Kim Môn","cn":"","aliases":["Bảy kim môn","Kim môn"],"loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"","soHuu":["Đường San"],"blurb":"Thần thông phòng hộ của đệ tam phi Đường San, triệu kim môn khổng lồ phát kim quang vạn trượng để đối kháng công kích.","detail":"Kim môn khổng lồ trôi tới phát kim quang vạn trượng đối kháng tiếng gầm. Bị tiếng gầm Dĩ Ti Chi Khôi phá hủy liên tiếp, bốn luồng kim quang cũng vỡ vụn. Chuỗi hạt châu sư tôn ban tặng có thể hóa thành bảy kim môn đồng thời hiện ra, uy lực mạnh hơn.","congNang":["Triệu kim môn phòng hộ, phát kim quang đối kháng công kích"],"nguoiTu":[{"ten":"Đường San","tuChuong":"@c1675","tangDatToi":"","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1675","loai":"thi triển","importance":"normal","giaiDoan":"Đệ tam phi dùng kim môn chống Dĩ Ti Chi Khôi","text":"Đệ tam phi dùng kim môn phòng hộ chống tiếng gầm Dĩ Ti Chi Khôi, kim môn liên tục bị phá vỡ, bốn luồng kim quang cũng vỡ vụn.","anchor":"Kim môn lập tức phát ra kim quang vạn trượng, đối kháng với tiếng gầm kia"}]},"nguon":["@c1675"]},{"id":"bat-dao-tram-than-hon","name":"Bát Đao Trảm Thần Hồn","cn":"八刀斩神魂","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Không rõ","soHuu":["Vân Dật Phong"],"blurb":"Thần thông của Vân Dật Phong: từ đám sương đen rút bảy trường đao, phân thân thành bảy, bảy thân nối liền tạo hình đao thứ tám khai thiên.","detail":"Từ đám sương đen lấy ra bảy thanh trường đao, phân thân thành bảy bản thể. Hai thân làm cán đao, bốn thân làm thân đao, một thân làm ngọn đao — bảy thân nối liền tạo hình đao thứ tám khổng lồ khai thiên. Bị Vương Lâm dùng Tê Thiên Thuật đại thành phá tan lần đầu, sau đó Vân Dật Phong uống đan dược thi triển lại để tấn công Chưởng Tôn.","congNang":["Phân thân thành bảy bản thể, bảy đao hợp nhất thành đao thứ tám khai thiên có uy lực cự đại"],"nguoiTu":[{"ten":"Vân Dật Phong","tuChuong":"@c1676","tangDatToi":"Không rõ","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1676","loai":"thi triển","importance":"major","giaiDoan":"Xuất hiện và thi triển","text":"Vân Dật Phong thi triển Bát Đao Trảm Thần Hồn đấu Vương Lâm, bị phá tan hoàn toàn bởi Tê Thiên Thuật đại thành. Sau đó uống đan dược thi triển lại để tấn công Chưởng Tôn.","anchor":"Bát đao trảm thần hồn!"}]},"nguon":["@c1676"]},{"id":"chuong-diet-tam-dao","name":"Chưởng diệt tam đạo","cn":"掌灭三道","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Không rõ","soHuu":["Chưởng Tôn"],"blurb":"Thần thông ba tầng của Chưởng Tôn: Đệ nhất diệt linh đạo, Đệ nhị diệt quỷ đạo, Đệ tam diệt thần đạo — tầng cuối phun máu vàng hóa kim ấn khổng lồ.","detail":"Thần thông liên hoàn ba tầng. Đệ nhất diệt linh đạo: vòng tròn hai tay phóng kim quang kiếm sắc vô số. Đệ nhị diệt quỷ đạo: hiện sơ dương phía sau lưng, tràn ngập sức mạnh thái sơ quy tắc. Đệ tam diệt thần đạo: phun máu vàng ngưng tụ thành kim ấn khổng lồ. Kim ấn tầng ba vượt qua Tê Thiên Thuật của Vương Lâm nhưng bị Huyền La biến thành pháp bảo thực chất.","congNang":["Tấn công liên hoàn ba tầng, mỗi tầng mạnh hơn tầng trước","Tầng ba phun máu vàng hóa kim ấn khổng lồ"],"nguoiTu":[{"ten":"Chưởng Tôn","tuChuong":"@c1677","tangDatToi":"Đệ tam diệt thần đạo","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1677","loai":"thi triển","importance":"major","giaiDoan":"Lần đầu xuất hiện","text":"Chưởng Tôn thi triển đầy đủ ba tầng đối đầu Tê Thiên Thuật của Vương Lâm. Hai tầng đầu bị phá nhưng kim ấn tầng ba vượt qua giáng xuống Vương Lâm. Kim ấn sau đó bị Huyền La biến thành pháp bảo thực chất.","anchor":"Chưởng diệt tam đạo! Đệ nhất diệt linh đạo!"}]},"nguon":["@c1677"]},{"id":"nang-luc-bien-than-thong-thanh-phap-bao","name":"Năng lực biến thần thông hư ảo thành pháp bảo thực chất","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Cấp cửu đại thiên tôn","hePhai":"Tiên Cương Cửu Dương","soHuu":["Huyền La Đại Thiên Tôn"],"blurb":"Năng lực cấp cửu đại thiên tôn: biến vật do thần thông biến hóa ra thành thực chất, gọi là thay trời đổi đất, lấy tạo hóa sinh vật.","detail":"Huyền La chỉ tay dừng kim ấn (vốn là thần thông hư ảo do Chưởng Tôn ngưng tụ) rồi biến nó thành vật thực chất — một pháp bảo thật sự. Chưởng Tôn xác nhận đây là năng lực thay trời đổi đất, lấy tạo hóa sinh vật, chỉ cửu đại thiên tôn thuộc Tiên Cương Cửu Dương mới làm được.","congNang":["Biến vật do thần thông biến hóa ra thành thực chất, tạo ra pháp bảo thật sự từ hư không"],"nguoiTu":[{"ten":"Huyền La Đại Thiên Tôn","tuChuong":"@c1677","tangDatToi":"Không rõ","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1677","loai":"thi triển","importance":"major","giaiDoan":"Lần đầu lộ diện","text":"Huyền La tùy ý chỉ tay biến kim ấn hư ảo của Chưởng Tôn thành pháp bảo thực chất lơ lửng trước Vương Lâm, khiến Chưởng Tôn kinh hãi nhận ra thân phận cửu đại thiên tôn.","anchor":"Biến vật do thần thông biến hoá ra trở thành thực chất, chuyện thay trời đổi đất này, năng lực lấy tạo hoá để sinh vật này"}]},"nguon":["@c1677"]},{"id":"tinh-trung-lao-nguyet","name":"Tình Trung Lao Nguyệt","cn":"情中撈月","aliases":["Tĩnh Trung Lao Nguyệt"],"loai":"bi-thuat","loaiLabel":"Đạo thuật","phamCap":"Không rõ","hePhai":"Chưởng Tôn","soHuu":["Chưởng Tôn"],"blurb":"Đạo thuật lấy mặt đất làm giếng, phản chiếu bầu trời, từ trong giếng mò ra ảo ảnh để giết hồn đối phương.","detail":"Chưởng Tôn thi triển đạo thuật này khi bị dồn vào đường cùng. Lấy mặt đất làm giếng, phản chiếu hết thảy trên bầu trời, từ trong giếng mò ra những ảo ảnh. Là thuật lấy hồn để giết, Vương Lâm đã từng thấy qua vài lần trước đó, mỗi lần đều mang lại chấn động sâu đậm.","congNang":["Lấy mặt đất làm giếng phản chiếu bầu trời, mò ra ảo ảnh giết hồn"],"nguoiTu":[{"ten":"Chưởng Tôn","tuChuong":"@c1678","tangDatToi":"Không rõ","trangThai":"dang-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c1678","loai":"thi triển","importance":"major","giaiDoan":"Chưởng Tôn thi triển lần đầu trong trận","text":"Chưởng Tôn bị thương nặng, chỉ tay lên trời thi triển Tình Trung Lao Nguyệt — lấy mặt đất làm giếng, phản chiếu hết thảy trên bầu trời, mò ra ảo ảnh giết hồn. Vương Lâm nhận ra đây là thuật lấy hồn để giết đã từng thấy vài lần.","anchor":"lấy mặt đất làm giếng, phản chiếu hết thảy trên bầu trời, từ trong giếng mò ra những ảo ảnh"}]},"nguon":["@c1678"]},{"id":"than-thong-ac-hau-tim","name":"Thần thông ác hầu tím","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Tiên Cương đại lục","soHuu":["Vân Dật Phong"],"blurb":"Thần thông từ Tiên Cương đại lục, tử quang hóa thành con khỉ màu tím, nhập thể kẻ địch theo thất khiếu phá hoại từ bên trong.","detail":"Vân Dật Phong thi triển tử quang hóa thành con khỉ màu tím tấn công Chưởng Tôn. Ác hầu theo thất khiếu nhập thể, xuất hiện hư ảnh trên mi tâm đối phương, gây cảm giác thân thể bị xé rách. Nguồn gốc từ Tiên Cương đại lục.","congNang":["Nhập thể kẻ địch qua thất khiếu, phá hoại từ bên trong","Xuất hiện hư ảnh trên mi tâm đối phương"],"nguoiTu":[{"ten":"Vân Dật Phong","tuChuong":"@c1678","tangDatToi":"Không rõ","trangThai":"dang-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c1678","loai":"thi triển","importance":"normal","giaiDoan":"Vân Dật Phong thi triển lần đầu trong trận vây Chưởng Tôn","text":"Vân Dật Phong hóa thần thông thành con khỉ màu tím, nhập thể Chưởng Tôn theo thất khiếu, xuất hiện hư ảnh trên mi tâm hắn.","anchor":"bị thần thông từ Tiên Cương đại lục của Vân Dật Phong kia nhập thể"}]},"nguon":["@c1678"]},{"id":"that-mon-hop-nhat-kim-long","name":"Thất môn hợp nhất — Kim long","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Đường San (đệ tam phi)","soHuu":["Đường San"],"blurb":"Thần thông của Đường San, dùng hạt châu vàng triệu kim môn, thất môn hợp nhất hóa cự long màu vàng tấn công.","detail":"Đường San vung hạt châu vàng trên cổ tay, kim môn xuất hiện, thất môn hợp nhất, kim quang tràn ngập hóa thành cự long màu vàng lao ra tấn công đối phương.","congNang":["Hợp bảy cửa kim môn thành cự long vàng tấn công"],"nguoiTu":[{"ten":"Đường San","tuChuong":"@c1678","tangDatToi":"Thất môn hợp nhất","trangThai":"dang-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c1678","loai":"thi triển","importance":"normal","giaiDoan":"Đường San lần đầu thi triển thất môn hợp nhất","text":"Đường San vung hạt châu vàng, kim môn xuất hiện, thất môn hợp nhất hóa cự long màu vàng lao vào Chưởng Tôn.","anchor":"kim môn xuất hiện, lập tức dung hợp lại với nhau, sau khi thất môn hợp nhất"}]},"nguon":["@c1678"]},{"id":"phong-an-tu-ky-hieu-lam-mong","name":"Phong ấn tứ ký hiệu của Lam Mộng","cn":"","loai":"bi-thuat","loaiLabel":"Liên hợp thuật","phamCap":"","hePhai":"","soHuu":["Lam Mộng Đạo Tôn"],"blurb":"Liên hợp thuật do Lam Mộng Đạo Tôn làm chủ đạo, phối hợp ba người khác dung hợp lam quang tạo bốn ký hiệu phong ấn, phong bế toàn thân đối thủ cấp huyền kiếp trong ba nhịp thở.","detail":"Lam Mộng dùng tu vi cả đời hóa lam quang, kéo Vân Dật Phong, Đường San, Thác Sâm dung hợp vào lam quang, ngưng tụ ra bốn ký hiệu phong ấn đánh thẳng lên người đối thủ. Đã dùng để phong ấn Chưởng Tôn ba nhịp thở trong trận chiến tại tầng hai cổ mộ.","congNang":["Phong ấn toàn thân đối thủ cấp huyền kiếp trong ba nhịp thở khi phối hợp bốn người"],"nguon":["@c1679"],"tabs":{"tienTrinh":[{"chuong":"@c1679","loai":"thi triển","importance":"major","giaiDoan":"Lần đầu thi triển","text":"Lam Mộng Đạo Tôn dùng tu vi cả đời làm chủ đạo, phối hợp Vân Dật Phong, Đường San, Thác Sâm dung hợp lam quang tạo bốn ký hiệu phong ấn, phong bế Chưởng Tôn ba nhịp thở, tạo cơ hội cho Vương Lâm dùng Mộng Đạo tế hồn.","anchor":"bốn ký hiệu phong ấn, trong lúc lam quang lóe lên lao thẳng tới Chưởng Tôn"}]}},{"id":"than-thong-nhip-tim","name":"Thần thông nhịp tim (đang cảm ngộ)","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Chưa rõ","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Thần thông Vương Lâm minh ngộ từ nhịp đập trái tim Diệp Mịch: dùng nhịp tim bản thân dẫn động nhịp tim đối phương, khiến vỡ tim hoặc khống chế. Kết hợp lôi bổn nguyên, Mộng Đạo và hư hỏa.","detail":"Vương Lâm cảm ngộ từ sự hòa nhịp với trái tim Diệp Mịch tại tầng cuối cùng vùng đất cổ mộ. Nguyên lý cốt lõi là dùng nhịp tim bản thân dẫn động nhịp tim đối phương, có thể khiến đối phương vỡ tim mà chết hoặc gián tiếp khống chế. Tính toán kết hợp lôi bổn nguyên (khuếch đại tiếng tim), Mộng Đạo (khiến đối phương sinh ảo giác thay đổi nhịp tim) và hư hỏa trong hỏa bổn nguyên (nhóm hư hỏa khi nhịp tim thay đổi). Chưa hoàn thành.","congNang":["Dùng nhịp tim bản thân dẫn động nhịp tim đối phương, khiến vỡ tim hoặc khống chế"],"dacDiem":"Kết hợp lôi bổn nguyên + Mộng Đạo + hư hỏa, đang trong giai đoạn cảm ngộ chưa hoàn chỉnh","nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1681","tangDatToi":"đang cảm ngộ","trangThai":"dang-tu"}],"trangThai":"đang cảm ngộ","tabs":{"tienTrinh":[{"chuong":"@c1681","loai":"xuất hiện","importance":"major","giaiDoan":"Cảm ngộ sơ bộ","text":"Vương Lâm minh ngộ nguyên lý dùng nhịp tim dẫn động nhịp tim đối phương từ sự hòa nhịp với trái tim Diệp Mịch. Tính toán kết hợp lôi bổn nguyên, Mộng Đạo và hư hỏa để sáng tạo thần thông mới, chưa hoàn thành.","anchor":"Dùng trái tim của bản thân dẫn động trái tim của người khác, thay đổi nhịp tim của đối phương"}]},"nguon":["@c1681"]},{"id":"ngu-hanh-kim-tien","name":"Ngũ hành kim tiên — Ngưng tụ kim thiên","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Chưa rõ","hePhai":"Ngũ Hành","soHuu":["Lão già họ Mã"],"blurb":"Thần thông ngũ hành của lão già họ Mã, kim quang bùng lên biến bầu trời thành dòng sông ánh sáng, từ đó vươn ra bàn tay kim sắc khổng lồ tấn công.","detail":"Lão già họ Mã thi triển tại tầng thứ hai vùng đất cổ mộ. Kim quang bùng lên biến bầu trời thành dòng sông ánh sáng, từ trời vươn ra bàn tay kim sắc khổng lồ đánh về phía Chiến lão quỷ.","congNang":["Biến bầu trời thành kim thiên, triệu bàn tay kim sắc khổng lồ tấn công"],"nguoiTu":[{"ten":"Lão già họ Mã","tuChuong":"@c1681","tangDatToi":"","trangThai":"da-thi-trien"}],"tabs":{"tienTrinh":[{"chuong":"@c1681","loai":"thi triển","importance":"normal","giaiDoan":"Lần đầu thi triển","text":"Lão già họ Mã thi triển tại ác chiến tầng thứ hai, biến bầu trời thành dòng sông kim quang, vươn bàn tay kim sắc khổng lồ đánh Chiến lão quỷ.","anchor":"Ngũ hành kim tiên! Ngưng tụ kim thiên!"}]},"nguon":["@c1681"]},{"id":"ngu-hanh-tho-tien","name":"Ngũ hành thổ tiên — Ngưng tụ hắc địa","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Chưa rõ","hePhai":"Ngũ Hành","soHuu":["Lão già họ Mã"],"blurb":"Thần thông ngũ hành của lão già họ Mã, biến mặt đất thành vùng hắc ám, vươn ra bàn tay hắc khổng lồ tấn công.","detail":"Lão già họ Mã thi triển tại tầng thứ hai vùng đất cổ mộ. Mặt đất hóa vùng hắc ám, từ đó vươn ra bàn tay hắc khổng lồ đánh về phía Chiến lão quỷ, phối hợp cùng bàn tay kim sắc từ trên trời.","congNang":["Biến mặt đất thành hắc địa, triệu bàn tay hắc sắc khổng lồ tấn công"],"nguoiTu":[{"ten":"Lão già họ Mã","tuChuong":"@c1681","tangDatToi":"","trangThai":"da-thi-trien"}],"tabs":{"tienTrinh":[{"chuong":"@c1681","loai":"thi triển","importance":"normal","giaiDoan":"Lần đầu thi triển","text":"Lão già họ Mã thi triển phối hợp cùng Ngũ hành kim tiên, biến mặt đất thành hắc địa, vươn bàn tay hắc khổng lồ đánh Chiến lão quỷ.","anchor":"Ngũ hành thổ tiên! Ngưng tụ hắc địa!"}]},"nguon":["@c1681"]},{"id":"tam-dong-loi-am","name":"Tâm Động Lôi Âm","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Thần thông mới của Vương Lâm sau truyền thừa Diệp Mịch, tiếng tim đập khuếch tán thành tiếng duy nhất trong thiên địa, dẫn động trái tim đối phương đau đớn không thể khống chế.","detail":"Tiếng tim đập từ trái tim Vương Lâm truyền ra khuếch tán khắp thiên địa, dẫn động tâm thần và trái tim đối phương, khiến trái tim đau đớn như bị xé nát. Ảnh hưởng diện rộng, kẻ huyền kiếp đỉnh phong như Chiến lão quỷ (dung hợp hồn phách Thất Thải Tiên Tôn) cũng không chống nổi. Huyền Vũ chiến tướng (gần Không Kiếp) cũng bị đánh bại.","thuocTinh":"Âm — Tâm thần","nguonGoc":"Đạt được sau khi hoàn thành truyền thừa Diệp Mịch","uyLuc":"Tiếng tim đập dẫn động tâm thần, khiến trái tim đối phương đau đớn sụp đổ, kẻ huyền kiếp đỉnh phong cũng không chống nổi","dacDiem":"Tiếng tim đập trở thành tiếng duy nhất trong thiên địa, ảnh hưởng diện rộng","congNang":["Tiếng tim đập dẫn động tâm thần đối phương, khiến trái tim đau đớn như bị xé nát (@c1682)"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1682","tangDatToi":"","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1682","loai":"thi triển","importance":"major","giaiDoan":"Lần đầu thi triển","text":"Vương Lâm phát động tiếng tim đập kinh thiên sau khi hoàn thành truyền thừa Diệp Mịch. Tiếng tim truyền vào tâm thần Chiến lão quỷ (dung hợp Thất Thải Tiên Tôn) khiến trái tim hắn đau đớn không thể khống chế. Trước đó tiếng tim cũng đánh bại Huyền Vũ chiến tướng ở cửa vào tầng cuối.","anchor":"tiếng thình thịch vang lên, giống như sấm dậy. Tiếng động từ trong thân thể Vương Lâm truyền ra"}]},"nguon":["@c1682"]},{"id":"ngan-muc","name":"Ngân Mục","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Đệ nhất tượng trong cửu khúc tam tượng","hePhai":"Cổ Tộc","soHuu":["Vương Lâm"],"blurb":"Hai mắt biến thành màu bạc, đệ nhất tượng trong cửu khúc tam tượng, nhờ hồn huyết cổ Tổ kết hợp truyền thừa Diệp Mịch. Cho phép nhìn thấy những điều người khác không thấy.","detail":"Thuộc hệ thống cửu khúc tam tượng (biểu hiện khi tiên tổ/cổ Tổ giáng trần). Tám tướng là tiên, cửu khúc là cổ; lưỡng khúc (đệ nhất tượng) = ngân mục kim thân. Lão già họ Mã khẳng định chỉ truyền thừa Diệp Mịch không đủ, ngay cả Diệp Mịch cũng không có ngân mục — cần hồn huyết cổ Tổ. Vương Lâm dùng ngân mục nhìn qua Huyền La Đại Thiên Tôn, mơ hồ thấy được điều gì đó mà không ai khác nhìn thấy.","thuocTinh":"Cổ Tộc — Thị giác","nguonGoc":"Hồn huyết cổ Tổ + truyền thừa Diệp Mịch","uyLuc":"Tăng thị giác siêu phàm, nhìn xuyên bản chất","dacDiem":"Đệ nhất tượng / lưỡng khúc trong cửu khúc tam tượng, mắt hai bên đều biến thành màu bạc","congNang":["Nhìn thấy những điều người khác không thấy (@c1682)"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1682","tangDatToi":"","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c1682","loai":"xuất hiện","importance":"major","giaiDoan":"Lần đầu xuất hiện","text":"Hai mắt Vương Lâm biến thành ngân mục sau hoàn thành truyền thừa Diệp Mịch nhờ hồn huyết cổ Tổ. Huyền La Đại Thiên Tôn kích động nhận ra đây là đệ nhất tượng trong cửu khúc. Lão già họ Mã nhớ truyền thuyết lưỡng khúc là ngân mục kim thân.","anchor":"Hai mắt màu bạc! Nghe đồn tiên tổ khi giáng trần có cửu khúc tam tượng"}]},"nguon":["@c1682"]},{"id":"cuu-khuc-tam-tuong","name":"Cửu khúc tam tượng","cn":"","loai":"khac","loaiLabel":"Hệ thống cảnh giới/biểu hiện","phamCap":"","hePhai":"Cổ Tộc / Tiên tộc","soHuu":[],"blurb":"Truyền thuyết về biểu hiện khi tiên tổ/cổ Tổ giáng trần: tám tướng là tiên, cửu khúc là cổ. Đệ nhất tượng (lưỡng khúc) là ngân mục kim thân.","detail":"Tiên tổ khi giáng trần có cửu khúc tam tượng, cổ Tổ năm đó giáng trần cũng tương tự. Nhất tượng: thiên địa bị phong bế đen kịt. Tám tướng là tiên, cửu khúc là cổ. Lưỡng khúc = ngân mục kim thân (đệ nhất tượng). Các tầng khác chưa rõ.","congNang":["Hệ thống biểu hiện quyền năng tiên tổ/cổ Tổ khi giáng trần (@c1682)"],"tabs":{"tienTrinh":[{"chuong":"@c1682","loai":"hé lộ tầng-chiêu","importance":"major","giaiDoan":"Lần đầu đề cập","text":"Lão già họ Mã nhớ lại truyền thuyết cửu khúc tam tượng khi nhìn thấy ngân mục Vương Lâm. Huyền La Đại Thiên Tôn xác nhận hồn huyết cổ Tổ khiến Vương Lâm đạt đệ nhất tượng.","anchor":"Thiên địa bị phong bế đen kịt là nhất tượng! Nghe đồn cửu khúc tam tượng này cũng giống như cổ Tổ năm đó giáng trần"}]},"nguon":["@c1682"]},{"id":"dao-co-vo-tien","name":"Đạo Cổ Vô Tiên","cn":"道古無仙","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Tuyệt học Đạo cổ","hePhai":"Đạo cổ nhất mạch","soHuu":["Vương Lâm"],"blurb":"Tuyệt chiêu dung hợp sức mạnh tam tộc Đạo cổ (Cổ Thần, Cổ Yêu, Cổ Ma), triệu ra hư ảnh đầu lâu Cổ Tổ hóa đá thiên địa. Gốc từ thần miếu bộ tộc Đạo cổ, truyền thừa qua Diệp Mịch.","detail":"Gồm ba bước liên hoàn: (1) Thần Chấn binh tu liệt vị — dùng Cổ Thần cửu tinh xoay thiên địa quanh quyền; (2) Yêu Thuật phong hỏa thành sơn — dùng Cổ Yêu bát tinh tạo tám cột phong hỏa nối thành lốc; (3) Ma Đạo sinh tử nghịch động — dùng Cổ Ma cửu tinh chuyển hóa sức sống thành tử khí, ngưng tử khí từ vô số sinh linh thành biển chết. Cuối cùng dung hợp cả ba thành một chưởng, triệu ra hư ảnh đầu lâu Cổ Tổ khổng lồ cao ngang thiên địa, phun khí tức hóa đá toàn bộ vùng đất. Điều kiện: cần Cổ Thần cửu tinh + Cổ Ma cửu tinh + Cổ Yêu (hiện bát tinh, thiếu mắt trái nên chưa cửu tinh). Dùng xong kiệt sức, không thể thi triển lần hai trong thời gian ngắn.","thuocTinh":"Đạo cổ tam tộc","nguonGoc":"Thần miếu bộ tộc Đạo cổ, truyền thừa Diệp Mịch","yeuCau":"Cổ Thần cửu tinh + Cổ Ma cửu tinh + Cổ Yêu bát tinh trở lên","uyLuc":"Hóa đá toàn bộ cổ mộ nhiều tầng cùng Chiến lão quỷ và hai hồn Thất Thải Tiên Tôn","dacDiem":"Dung hợp sức mạnh ba nhánh Cổ tộc thành một, triệu hư ảnh Cổ Tổ — tuyệt học mạnh nhất trong truyền thừa Diệp Mịch","congNang":["Dung hợp Cổ Thần cửu tinh + Cổ Ma cửu tinh + Cổ Yêu bát tinh thành một chưởng @c1683","Triệu hư ảnh đầu lâu Cổ Tổ khổng lồ hóa đá thiên địa @c1683"],"cacTang":[{"ten":"Thần Chấn — Binh Tu Liệt Vị","moTa":"Cổ Thần cửu tinh xoay tròn dung nhập quyền, thiên địa xoay quanh","chuong":"@c1683"},{"ten":"Yêu Thuật — Phong Hỏa Thành Sơn","moTa":"Cổ Yêu bát tinh tạo tám cột phong hỏa nối thành lốc","chuong":"@c1683"},{"ten":"Ma Đạo — Sinh Tử Nghịch Động","moTa":"Cổ Ma cửu tinh chuyển hóa sức sống thành tử khí, ngưng tử khí từ toàn bộ cổ mộ","chuong":"@c1683"}],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1683","tangDatToi":"Hợp nhất tam tộc","trangThai":"dang-tu"}],"trangThai":"hoat-dong","capNhatToi":"@c1683","dinhDanh":"goc","tabs":{"tienTrinh":[{"chuong":"@c1683","loai":"thi-trien","importance":"major","giaiDoan":"Lần đầu thi triển","text":"Vương Lâm lần đầu thi triển Đạo Cổ Vô Tiên tại cổ mộ, dung hợp tam tộc triệu ra hư ảnh đầu lâu Cổ Tổ hóa đá toàn bộ cổ mộ và Chiến lão quỷ cùng hai hồn Thất Thải. Dù kiệt sức, Chiến lão quỷ vẫn phá hóa đá thoát thân.","anchor":"Thần. Yêu. Ma. Đạo cổ vô tiên!"}]},"nguon":["@c1683"]},{"id":"than-chan-binh-tu-liet-vi","name":"Thần Chấn — Binh Tu Liệt Vị","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Bước 1 Đạo Cổ Vô Tiên","hePhai":"Cổ Thần","soHuu":["Vương Lâm"],"blurb":"Bước đầu tiên của Đạo Cổ Vô Tiên, dùng Cổ Thần cửu tinh xoay tròn dung nhập vào quyền, khiến thiên địa xoay quanh vị trí quyền.","detail":"Chín tinh điểm Cổ Thần xoay tròn dung nhập vào quyền, biến quyền thành trung tâm thiên địa. Vương Lâm bất động, vạn vật xoay quanh. Gốc từ truyền thừa Diệp Mịch, học được tại thần miếu bộ tộc Đạo cổ.","nguonGoc":"Truyền thừa Diệp Mịch, thần miếu bộ tộc Đạo cổ","congNang":["Biến quyền thành trung tâm thiên địa, buộc vạn vật xoay quanh @c1683"],"dinhDanh":"goc","boCha":"dao-co-vo-tien","tabs":{"tienTrinh":[{"chuong":"@c1683","loai":"thi-trien","importance":"normal","giaiDoan":"Lần đầu thi triển","text":"Vương Lâm dùng Thần Chấn khiến thiên địa xoay quanh quyền, Chiến lão quỷ sắc mặt đại biến.","anchor":"Thiên địa xoay tròn, chỉ có Vương Lâm là bất động"}]},"nguon":["@c1683"]},{"id":"yeu-thuat-phong-hoa-thanh-son","name":"Yêu Thuật — Phong Hỏa Thành Sơn","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Bước 2 Đạo Cổ Vô Tiên","hePhai":"Cổ Yêu","soHuu":["Vương Lâm"],"blurb":"Bước thứ hai của Đạo Cổ Vô Tiên, dùng Cổ Yêu bát tinh dung nhập chưởng tạo tám cột khói phong hỏa có hư ảnh cổ Yêu gào thét, nối thành cơn lốc.","detail":"Tám yêu tinh trong mắt trái dung nhập vào chưởng, hình thành tám cột khói phong hỏa với hư ảnh cổ Yêu gào thét, nối liền tạo thành cơn lốc bao quanh Vương Lâm, kiêm phòng ngự và tấn công.","congNang":["Tạo tám cột phong hỏa nối thành lốc bao quanh, kiêm phòng ngự và tấn công @c1683"],"dinhDanh":"goc","boCha":"dao-co-vo-tien","tabs":{"tienTrinh":[{"chuong":"@c1683","loai":"thi-trien","importance":"normal","giaiDoan":"Lần đầu thi triển","text":"Vương Lâm thi triển Yêu Thuật tạo tám cột phong hỏa nối thành lốc bao quanh thân.","anchor":"tám cột khói phong hỏa này giống như là nối liền với nhau, tạo thành một cơn lốc"}]},"nguon":["@c1683"]},{"id":"ma-dao-sinh-tu-nghich-dong","name":"Ma Đạo — Sinh Tử Nghịch Động","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Bước 3 Đạo Cổ Vô Tiên","hePhai":"Cổ Ma","soHuu":["Vương Lâm"],"blurb":"Bước thứ ba của Đạo Cổ Vô Tiên, dùng Cổ Ma cửu tinh chuyển hóa sức sống đối phương thành tử khí, đồng thời triệu tử khí từ vô số sinh linh biến thiên địa thành biển chết.","detail":"Vương Lâm chỉ vào mục tiêu, sức sống trong cơ thể đối phương nhanh chóng chuyển hóa thành tử khí. Đồng thời triệu tập tử khí từ vô số sinh linh đã chết trong toàn bộ cổ mộ, biến thiên địa thành biển chết bao phủ.","congNang":["Chuyển hóa sức sống đối phương thành tử khí, ngưng tử khí từ vô số sinh linh thành biển chết bao phủ @c1683"],"dinhDanh":"goc","boCha":"dao-co-vo-tien","tabs":{"tienTrinh":[{"chuong":"@c1683","loai":"thi-trien","importance":"normal","giaiDoan":"Lần đầu thi triển","text":"Vương Lâm thi triển Ma Đạo biến sức sống Chiến lão quỷ thành tử khí, ngưng tử khí toàn cổ mộ thành biển chết.","anchor":"hắn lập tức cảm nhận được sức sống trong cơ thể đang nhanh chóng chuyển hóa biến thành tử khí"}]},"nguon":["@c1683"]},{"id":"van-dao-thien-thuat","name":"Vân Đạo Thiên Thuật","cn":"云道天术","aliases":[],"loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Tam đại tối cường thần thông Đông Lâm Tông","hePhai":"Đông Lâm Tông","soHuu":["Vương Lâm","Thất Thải Tiên Tôn"],"blurb":"Một trong tam đại tối cường thần thông của Đông Lâm Tông, mỗi thế hệ chỉ truyền cho một người duy nhất.","detail":"Khẩu quyết nhập môn yêu cầu vận chuyển vân khí trong thân thể một vòng, mây mù bao phủ — mỏng thì không đủ tư cách, nồng đậm có hư ảnh biến ảo là tốt nhất. Tốc độ vận chuyển cũng là tiêu chí chọn lựa, kỷ lục nhanh nhất Đông Lâm Tông là bảy nhịp thở. Vương Lâm đạt tám nhịp thở, mây mù tràn ngập phân nửa đại điện hóa thành rồng lớn. Khẩu quyết có câu biến tấu từ Đạo Đức Kinh.","thuocTinh":"Vân đạo","nguonGoc":"Đông Lâm Tông tam đại tối cường thần thông","dacDiem":"Mỗi thế hệ chỉ một người được học","congNang":["Vận chuyển vân khí tạo mây mù biến ảo, có thể hóa rồng nuốt sương mù đối thủ"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1685","tangDatToi":"Khẩu quyết nhập môn","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1685","loai":"xuất hiện","importance":"major","giaiDoan":"Lộ diện, Vương Lâm đạt tư cách học","text":"Sư tôn Liên Đạo Phi truyền khẩu quyết nhập môn Vân Đạo Thiên Thuật, tổ chức cuộc thử thách giữa Tô Đạo và Chu Lập. Vương Lâm nghịch chuyển ký ức, tám nhịp thở vận chuyển xong, mây mù hóa rồng nuốt sương mù Chu Lập, giành tư cách đệ tử chính hệ.","anchor":"một trong tam đại tối cường thần thông của Đông Lâm Tông"}]},"nguon":["@c1685","@c1688"]},{"id":"that-thai-tien-thuat","name":"Thất Thải Tiên Thuật","cn":"","aliases":[],"loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"Thuật pháp bậc nhất Đông Lâm Tông","hePhai":"Đông Lâm Tông","soHuu":["Chu Lập"],"blurb":"Thuật pháp bậc nhất của Đông Lâm Tông, được truyền cho người không đủ tư cách học Vân Đạo Thiên Thuật.","detail":"Trong ký ức gốc, Tô Đạo nhận thuật này vì thua cuộc thử thách vân khí. Sau khi Vương Lâm nghịch chuyển ký ức, Chu Lập trở thành người nhận Thất Thải Tiên Thuật thay thế.","nguonGoc":"Đông Lâm Tông","nguoiTu":[{"ten":"Thất Thải Tiên Tôn","tuChuong":"@c1685","tangDatToi":"Không rõ","trangThai":"ky-uc-goc"},{"ten":"Chu Lập","tuChuong":"@c1685","tangDatToi":"Không rõ","trangThai":"ky-uc-nghich-chuyen"}],"tabs":{"tienTrinh":[{"chuong":"@c1685","loai":"xuất hiện","importance":"normal","giaiDoan":"Hé lộ trong cuộc truyền thừa","text":"Thuật pháp bậc nhất Đông Lâm Tông, truyền cho người thua trong cuộc thử thách chọn truyền nhân Vân Đạo Thiên Thuật. Ký ức gốc Tô Đạo nhận, ký ức nghịch chuyển Chu Lập nhận.","anchor":"vi sư sẽ truyền Thất Thải Tiên Thuật cho ngươi"}]},"nguon":["@c1685"]},{"id":"bon-nguyen-chan-than","name":"Bổn Nguyên Chân Thân","cn":"本源真身","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Đạo Cổ","soHuu":["Vương Lâm"],"blurb":"Khi bổn nguyên đạt viên mãn, mỗi đạo ngưng tụ thành một chân thân hình dáng giống chủ nhân, mang đặc trưng riêng của từng bổn nguyên.","detail":"Bổn nguyên tiến hóa tới viên mãn sẽ ngưng tụ ra chân thân — hình thái tu luyện bổn nguyên mà Vương Lâm chưa từng nghe thấy trước đó. Tám chân thân tương ứng tám đạo bổn nguyên (hỏa, lôi, sinh tử, nhân quả, chân giả, sát lục, cấm chế, thủy), mỗi chân thân mang đặc trưng riêng. Tám chân thân có thể cùng đánh ra chưởng tạo uy lực khổng lồ. Nếu có bổn nguyên thứ chín sẽ đạt cửu cửu quy nhất, bước vào Không Huyền.","congNang":["Mỗi bổn nguyên viên mãn ngưng tụ một chân thân mang đặc trưng riêng","Tám chân thân cùng xuất chiêu gia tăng uy lực cực lớn","Chín chân thân sẽ cửu cửu quy nhất, có thể bước vào Không Huyền"],"cacTang":[{"ten":"Tám bổn nguyên chân thân","moTa":"Hỏa, lôi, sinh tử, nhân quả, chân giả, sát lục, cấm chế, thủy — mỗi đạo một chân thân","chuong":"@c1689"},{"ten":"Cửu cửu quy nhất (chưa đạt)","moTa":"Cần bổn nguyên thứ chín để hoàn thành, bước vào Không Huyền","chuong":"@c1689"}],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1689","tangDatToi":"Tám bổn nguyên chân thân (hư ảo trong ký ức)","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1689","loai":"xuất hiện","importance":"major","giaiDoan":"Lần đầu xuất hiện — tám chân thân ngưng tụ","text":"Vương Lâm nhập Đông Lâm Trì, bảy đạo bổn nguyên đạt viên mãn lần lượt ngưng tụ thành bảy chân thân. Thủy bổn nguyên hấp thu nước ao còn lại đại thành, ngưng tụ chân thân thứ tám. Tám chân thân cùng đánh ra chưởng mở đại môn động phủ giới.","anchor":"bổn nguyên tiến hóa, ngưng tụ ra chân thân của bổn nguyên mà hắn chưa bao giờ nghe thấy"}]},"nguon":["@c1689"]},{"id":"thien-duong-luan-hoi-chuyen-the-thuat","name":"Thiên Dương luân hồi chuyển thế thuật","cn":"天阳轮回转世术","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ (cực cao, Đại Thiên Tôn thi triển)","hePhai":"Đạo Cổ nhất mạch","soHuu":["Huyền La Đại Thiên Tôn"],"blurb":"Thần thông của Huyền La Đại Thiên Tôn, cho phép sinh linh chuyển thế đầu thai tại Tiên Cương đại lục với huyết mạch bản địa, đối kháng quy tắc cấm sinh linh không có huyết mạch.","detail":"Huyền La đề xuất thi triển để đưa bằng hữu Vương Lâm rời động phủ giới tới Tiên Cương đại lục. Sinh linh chuyển thế sẽ sinh ra lại với huyết mạch bản địa nhưng trí nhớ bị phủ kín hoàn toàn, cần người tìm tới thức tỉnh. Thời gian đầu thai bất định từ vài năm tới ngàn năm, địa điểm cũng không xác định. Huyền La phải trả giá rất lớn để thi triển. Không áp dụng cho hồn phách không hoàn chỉnh (như Uyển Nhi).","thuocTinh":"Luân hồi, chuyển thế","nguonGoc":"Huyền La Đại Thiên Tôn sở hữu","uyLuc":"Đối kháng pháp tắc Tiên Cương đại lục do Cổ Tổ và Tiên Tổ định ra","dacDiem":"Trí nhớ bị phủ kín, thời gian và địa điểm đầu thai bất định, đại giá cho người thi triển","congNang":["Chuyển thế đầu thai sinh linh tại Tiên Cương đại lục, sinh ra với huyết mạch bản địa","Đối kháng quy tắc huyết mạch Tiên Cương"],"nguoiTu":[{"ten":"Huyền La Đại Thiên Tôn","tuChuong":"@c1692","tangDatToi":"Không rõ","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c1692","loai":"xuất hiện","importance":"major","giaiDoan":"Đề xuất lần đầu","text":"Huyền La Đại Thiên Tôn đề xuất thi triển Thiên Dương luân hồi chuyển thế thuật để đối kháng pháp tắc Tiên Cương, đưa bằng hữu Vương Lâm chuyển thế đầu thai tại Tiên Cương đại lục.","anchor":"thi triển Thiên Dương luân hồi chuyển thế thuật"}]},"nguon":["@c1692"]}]};
